def build_prompt(itype, role, feedback):
    style = INTERVIEWER_TYPES[itype]
    # תמיד מבקשים פידבק פנימי – גם אם המשתמש לא רואה אותו
    fb = "\nאחרי כל תשובה ספק בשורה נפרדת: [פידבק: ציון X/10 | חוזקות: ... | לשיפור: ...]"
    return (f"אתה מראיין עבודה בעברית לתפקיד: {role}.\n{style}{fb}\n"
            "כללים חשובים:\n"
            "1. עברית בלבד.\n"
            "2. שאלה אחת בכל פעם.\n"
            "3. אסור בהחלט לכתוב דוגמאות, רמזים, או תשובות אפשריות בשאלה. לדוגמה: אל תכתוב 'כגון X, Y, Z' – שאל רק את השאלה הגולמית.\n"
            "4. 8-10 שאלות ואז סיים.\n"
            "כשמסיימים אמור: \"תודה רבה על זמנך, הראיון הסתיים!\"\n"
            "התחל בברכה קצרה ושאלה ראשונה.")

def get_reply(history, sys_prompt):
    msgs = [{"role":"system","content":sys_prompt}] + history
    r = client.chat.completions.create(model=LLM_MODEL, messages=msgs, temperature=0.7, max_tokens=400)
    return r.choices[0].message.content

def analyze_answer(text):
    words = text.split(); n = len(words)
    # תשובה ריקה או מילה אחת-שתיים = ציון מינימלי
    if n == 0: return {"words":0,"confidence":5,"clarity":5,"professionalism":5}
    if n <= 3: return {"words":n,"confidence":8,"clarity":8,"professionalism":5}
    if n <= 6: return {"words":n,"confidence":15,"clarity":20,"professionalism":10}
    weak   = sum(1 for w in ["אולי","כנראה","בערך","לא יודע","אממ"] if w in text)
    strong = sum(1 for w in ["הצלחתי","הובלתי","פיתחתי","השגתי","יצרתי","ניהלתי","שיפרתי","בניתי"] if w in text)
    conf = max(20, min(100, 50 + strong*12 - weak*12 + min(n//4, 20)))
    if   n < 15: clar = 35
    elif n < 30: clar = 65
    elif n < 80: clar = 88
    else:        clar = 70
    prof_words = ["פרויקט","מערכת","ארכיטקטורה","תכנון","בדיקות","קוד","api","API",
                  "תהליך","צוות","לקוח","ניתוח","אלגוריתם","database","backend",
                  "frontend","git","docker","react","python","java","node","cloud"]
    prof_hits = sum(1 for w in prof_words if w.lower() in text.lower())
    prof = max(15, min(100, 30 + prof_hits*13 + min(n//8, 20)))
    return {"words":n, "confidence":conf, "clarity":clar, "professionalism":prof}

def extract_llm_scores(history):
    """מחלץ ציוני X/10 מהפידבק של ה-LLM בשיחה"""
    import re
    scores = []
    for msg in history:
        if msg["role"] == "assistant":
            # מחפש דפוס [פידבק: ציון X/10 ...]
            matches = re.findall(r"ציון\s*(\d+(?:\.\d+)?)/10", msg["content"])
            for m in matches:
                scores.append(float(m))
    return scores

def compute_scores(per_answer, history=None):
    # קודם מנסה לחלץ ציוני LLM מהשיחה
    if history:
        llm_scores = extract_llm_scores(history)
        if llm_scores:
            avg_llm = round(sum(llm_scores)/len(llm_scores), 1)
            # משתמש בציון LLM כציון כללי, ומשלים עם חישוב מקומי לשאר
            if per_answer:
                def avg(k): return round(sum(s[k] for s in per_answer)/len(per_answer)/10, 1)
                cl=avg("clarity"); pr=avg("professionalism")
                # ביטחון = ממוצע ציוני LLM (הכי קרוב לביטחון הכולל)
                return {"overall":avg_llm, "clarity":cl, "confidence":avg_llm, "professionalism":pr}
    # fallback – חישוב מקומי בלבד
    if not per_answer: return {"overall":0,"clarity":0,"confidence":0,"professionalism":0}
    def avg(k): return round(sum(s[k] for s in per_answer)/len(per_answer)/10, 1)
    cl=avg("clarity"); cf=avg("confidence"); pr=avg("professionalism")
    ov=round(cl*0.3+cf*0.35+pr*0.35, 1)
    return {"overall":ov, "clarity":cl, "confidence":cf, "professionalism":pr}

def extract_feedback_points(history):
    """מחלץ חוזקות ושיפורים מהפידבק שניתן בזמן הראיון"""
    import re
    strengths = []
    improvements = []
    bad_values = {"-", "...", ".", "", "לא צוין", "אין"}
    for msg in history:
        if msg["role"] == "assistant" and "פידבק" in msg["content"]:
            # חוזקות: מה שאחרי "חוזקות:"
            s_match = re.search(r"חוזקות:\s*([^|\[\]\n]+)", msg["content"])
            if s_match:
                val = s_match.group(1).strip().rstrip("|").strip()
                # נקה נקודות בסוף ורווחים
                val = val.rstrip(".").strip()
                if val and val not in bad_values and len(val) > 3 and not val.startswith("..."):
                    strengths.append(val)
            # לשיפור: מה שאחרי "לשיפור:"
            i_match = re.search(r"לשיפור:\s*([^|\[\]\n]+)", msg["content"])
            if i_match:
                val = i_match.group(1).strip().rstrip("]").strip()
                val = val.rstrip(".").strip()
                if val and val not in bad_values and len(val) > 3 and not val.startswith("..."):
                    improvements.append(val)
    return strengths, improvements

def get_analysis(history, scores):
    # קודם אוסף מהפידבק האמיתי
    strengths, improvements = extract_feedback_points(history)

    # אם מצאנו מספיק נקודות – משתמשים בהן ישירות
    if len(strengths) >= 2 and len(improvements) >= 2:
        avg = scores["overall"]
        if avg >= 8:
            tone = "ביצוע מצוין! הראית ידע מעמיק ותשובות בטוחות."
        elif avg >= 6:
            tone = "ביצוע טוב. הראית הבנה של התחום עם מקום לפיתוח נוסף."
        elif avg >= 4:
            tone = "ביצוע סביר. יש בסיס טוב, אך כדאי לעבוד על עומק התשובות ועל הצגת ניסיון."
        else:
            tone = "הראיון היה מאתגר. כדאי להתכונן יותר לשאלות בתחום ולתרגל הצגת ניסיון."
        summary = f"ציון כללי {avg}/10. {tone}"
        return {
            "strengths": strengths[:4],
            "improvements": improvements[:4],
            "summary": summary
        }

    # fallback – מבקש מ-LLM לחלץ מהשיחה
    conv = "\n".join(("מראיין" if m["role"]=="assistant" else "מועמד")+": "+m["content"] for m in history)
    prompt = (f"ציון כללי: {scores['overall']}/10\n"
              "חלץ מהשיחה הזו את החוזקות והשיפורים שצוינו בפידבק.\n"
              "החזר JSON בלבד:\n"
              '{"strengths":["חוזק מהפידבק1","חוזק מהפידבק2"],'
              '"improvements":["שיפור מהפידבק1","שיפור מהפידבק2"],'
              '"summary":"סיכום קצר"}\n'
              f"שיחה:\n{conv[:3000]}")
    r = client.chat.completions.create(model=LLM_MODEL,
        messages=[{"role":"user","content":prompt}], temperature=0.1, max_tokens=500)
    raw = r.choices[0].message.content.strip()
    import re as _re
    json_match = _re.search(r'\{.*\}', raw, _re.DOTALL)
    if json_match:
        try:
            result = json.loads(json_match.group())
            if "strengths" in result and "improvements" in result:
                return result
        except: pass
    return {
        "strengths": strengths if strengths else ["השתתפת בראיון"],
        "improvements": improvements if improvements else ["הרחב את תשובותיך"],
        "summary": f"ציון כללי {scores['overall']}/10."
    }

def do_tts(text):
    import subprocess, sys
    clean = re.sub(r"\[פידבק:.*?\]","",text).strip()
    if not clean: return None
    try:
        # נסה עם edge-tts (תומך עברית מצוין)
        import edge_tts, asyncio
        tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".mp3"); tmp.close()
        print(f"[TTS] generating: {clean[:40]}...")
        asyncio.run(edge_tts.Communicate(clean, "he-IL-AvriNeural").save(tmp.name))
        size = os.path.getsize(tmp.name)
        if size > 100:
            print(f"[TTS] OK – {size} bytes")
            return tmp.name
        print("[TTS] file too small")
        return None
    except Exception as e:
        print(f"[TTS ERROR] {type(e).__name__}: {e}")
        return None

def do_stt(audio_bytes):
    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".wav")
    tmp.write(audio_bytes); tmp.close()
    with open(tmp.name,"rb") as f:
        return client.audio.transcriptions.create(
            file=("rec.wav",f.read()), model=STT_MODEL,
            language="he", response_format="text").strip()

def make_chart(scores, history):
    """גרף אחד: התקדמות הציון הכללי לאורך הראיון – עברית מלאה"""
    import re
    matplotlib.rcParams["axes.unicode_minus"] = False
    matplotlib.rcParams["font.family"] = "DejaVu Sans"
    fig, ax = plt.subplots(1, 1, figsize=(11, 5), facecolor="#0f172a")
    fig.suptitle("InterviewMirror", color="white", fontsize=15, fontweight="bold")
    ax.set_facecolor("#1e293b")

    llm_scores = []
    for msg in history:
        if msg["role"] == "assistant":
            matches = re.findall(r"ציון\s*(\d+(?:\.\d+)?)/10", msg["content"])
            for m in matches:
                llm_scores.append(float(m))

    if llm_scores:
        x = list(range(1, len(llm_scores)+1))
        ax.plot(x, llm_scores, "o-", color="#6366f1", linewidth=2.5, markersize=9, label="Score per answer")
        avg = round(sum(llm_scores)/len(llm_scores), 1)
        ax.axhline(y=avg, color="#f59e0b", linestyle="--", linewidth=1.8, alpha=0.8, label=f"Average: {avg}/10")
        for xi, yi in zip(x, llm_scores):
            ax.text(xi, yi+0.25, str(yi), ha="center", color="white", fontsize=11, fontweight="bold")
        ax.set_xticks(x)
        ax.set_xticklabels([f"Answer {i}" for i in x], color="white", fontsize=10)
        ax.set_ylim(0, 11)
    else:
        ax.text(0.5, 0.5, "No data", ha="center", va="center",
                transform=ax.transAxes, color="white", fontsize=14)

    ax.set_ylabel("Score (/10)", color="white", fontsize=11)
    ax.set_title("Score Progress Throughout Interview", color="white", fontsize=13, pad=10)
    ax.tick_params(colors="white")
    ax.spines[:].set_color("#334155")
    ax.grid(axis="y", color="#334155", alpha=0.5)
    ax.legend(facecolor="#334155", labelcolor="white", fontsize=10)
    plt.tight_layout(rect=[0,0,1,0.93])
    return fig

