# ── טאב 2 ─────────────────────────────────────────────
with tab2:
    if not st.session_state.started:
        st.info("התחל ראיון בטאב הגדרות ראיון")
    else:
        for msg in st.session_state.history:
            with st.chat_message(msg["role"]):
                content = msg["content"]
                if not st.session_state.get("feedback_mode", True) and msg["role"] == "assistant":
                    import re as _re
                    content = _re.sub(r"\[פידבק:.*?\]", "", content, flags=_re.DOTALL)
                    content = _re.sub(r"\n{2,}", "\n", content).strip()
                st.markdown(content)
        if st.session_state.last_audio and os.path.exists(st.session_state.last_audio):
            with open(st.session_state.last_audio,"rb") as f:
                st.audio(f.read(), format="audio/mp3")

        if st.session_state.active:
            user_input  = st.chat_input("הקלד תשובתך כאן...")
            audio_input = st.audio_input("הקלט תשובה קולית",
                                         key=f"aud_{len(st.session_state.history)}")
            answer = None
            if user_input: answer = user_input
            elif audio_input is not None:
                ahash = hash(audio_input.read()); audio_input.seek(0)
                if ahash != st.session_state.get("last_audio_hash"):
                    st.session_state.last_audio_hash = ahash
                    with st.spinner("מתמלל..."): answer = do_stt(audio_input.read())
                    st.caption(f"זוהה: {answer}")
            if answer:
                # מציאת השאלה האחרונה שהמראיין שאל (הודעת ה-assistant האחרונה בהיסטוריה כרגע)
                last_question = "שאלה פותחת"
                for msg in reversed(st.session_state.history):
                    if msg["role"] == "assistant":
                        last_question = msg["content"]
                        break

                st.session_state.per_answer.append(analyze_answer(answer))
                st.session_state.history.append({"role":"user","content":answer})
                with st.spinner("המראיין חושב..."):
                    reply = get_reply(st.session_state.history, st.session_state.sys_prompt)
                st.session_state.history.append({"role":"assistant","content":reply})
                st.session_state.last_audio = do_tts(reply)
                
                # חילוץ הציון המספרי מתוך הפידבק של ה-AI (למשל מתוך "ציון 2/10")
                import re as _re
                score_match = _re.search(r"ציון\s*(\d+)", reply)
                extracted_score = int(score_match.group(1)) if score_match else None
                
                # שמירה ל-Firebase
                try:
                    save_response_to_db(
                        interview_id=st.session_state.get("interview_id"),
                        turn_index=len(st.session_state.history),
                        interviewer_type=st.session_state.get("itype", "טכני"),
                        job_role=st.session_state.get("job_role", "כללי"),
                        question=last_question,
                        user_answer=answer,
                        score=extracted_score, # ◄◄◄ עכשיו המשתנה הזה קיים ומחושב!
                        ai_feedback=reply
                    )
                    
                    # הריצה מחדש תקרה רק אם השמירה עברה בהצלחה
                    if "הראיון הסתיים" in reply:
                        st.session_state.active = False
                    st.rerun()

                except Exception as e:
                    # מונע rerun ומציג לך את השגיאה האמיתית על המסך אם משהו נדפק
                    st.error(f"שגיאה בשמירה ל-Firebase: {e}")
                    st.stop()
        else:
            st.success("הראיון הסתיים – עבור לטאב ניתוח ביצועים")

# ── טאב 3 ─────────────────────────────────────────────
with tab3:
    if not st.session_state.history:
        st.info("סיים ראיון תחילה")
    else:
        if st.button("הצג ניתוח מלא", type="primary", use_container_width=True):
            with st.spinner("מחשב ציונים..."):
                scores = compute_scores(st.session_state.per_answer, st.session_state.history)
                fig    = make_chart(scores, st.session_state.history)
            with st.spinner("מנתח..."):
                analysis = get_analysis(st.session_state.history, scores)
            st.pyplot(fig)
            st.markdown("---")
            st.markdown('<h3 style="direction:rtl;text-align:right">חוזקות</h3>', unsafe_allow_html=True)
            for s in analysis.get("strengths",[]): st.markdown(f'<p style="direction:rtl;text-align:right">• {s}</p>', unsafe_allow_html=True)
            st.markdown("---")
            st.markdown('<h3 style="direction:rtl;text-align:right">לשיפור</h3>', unsafe_allow_html=True)
            for s in analysis.get("improvements",[]): st.markdown(f'<p style="direction:rtl;text-align:right">• {s}</p>', unsafe_allow_html=True)
            st.markdown("---")
            st.markdown('<h3 style="direction:rtl;text-align:right">סיכום</h3>', unsafe_allow_html=True)
            st.info(analysis.get("summary",""))
